<?php
namespace App\Services\Customers; use App\Models\Customers\Customer; use App\Models\Customers\CustomerActivityLog; use App\Models\Customers\CustomerGroupMember; use App\Models\Customers\CustomerSetting; use App\Models\User; use App\Services\AuditLogger; use Illuminate\Support\Facades\DB;
class CustomerService { public function __construct(private readonly AuditLogger $audit,private readonly CustomerNumberService $numbers,private readonly CustomerEventService $events,private readonly LoyaltyService $loyalty){} /** @param array<string,mixed> $data */ public function create(User $user,array $data):Customer{return DB::transaction(function()use($user,$data){$customer=Customer::create($data+['company_id'=>$user->company_id,'branch_id'=>$data['branch_id']??$user->branch_id,'customer_number'=>$this->numbers->next($user->company_id),'display_name'=>trim($data['first_name'].' '.($data['last_name']??'')),'created_by'=>$user->id,'is_active'=>($data['status']??'active')==='active']);$settings=CustomerSetting::firstOrCreate(['company_id'=>$user->company_id]);if($settings->default_customer_group_id) CustomerGroupMember::firstOrCreate(['company_id'=>$user->company_id,'customer_id'=>$customer->id,'customer_group_id'=>$settings->default_customer_group_id],['assigned_at'=>now(),'assigned_by'=>$user->id]);if($settings->loyalty_enabled)$this->loyalty->ensureAccount($customer,$user);$this->activity($customer,$user,'created','Customer created');$this->audit->record('customer.created',$customer,'Customer created');$this->events->dispatch('customer.created',$user,$customer,['customer_name'=>$customer->display_name]);return $customer;});} /** @param array<string,mixed> $data */ public function update(Customer $customer,User $user,array $data):Customer{$before=$customer->status;$customer->update($data+['display_name'=>trim(($data['first_name']??$customer->first_name).' '.($data['last_name']??$customer->last_name??'')),'is_active'=>($data['status']??$customer->status)==='active']);$this->activity($customer,$user,'updated','Customer updated');$this->audit->record('customer.updated',$customer,'Customer updated');$this->events->dispatch('customer.updated',$user,$customer,['customer_name'=>$customer->display_name]);if($before!==$customer->status){$this->audit->record('customer.status.changed',$customer,'Customer status changed');$this->events->dispatch('customer.status.changed',$user,$customer,['status'=>$customer->status]);}return $customer->refresh();} public function delete(Customer $customer,User $user):void{$customer->delete();$this->activity($customer,$user,'updated','Customer moved to trash');$this->audit->record('customer.deleted',$customer,'Customer deleted');$this->events->dispatch('customer.deleted',$user,$customer);} public function restore(Customer $customer,User $user):Customer{$customer->restore();$this->audit->record('customer.restored',$customer,'Customer restored');$this->events->dispatch('customer.restored',$user,$customer);return $customer->refresh();} public function activity(Customer $customer,User $user,string $type,string $title,?string $description=null):void{CustomerActivityLog::create(['company_id'=>$customer->company_id,'customer_id'=>$customer->id,'activity_type'=>$type,'title'=>$title,'description'=>$description,'user_id'=>$user->id,'occurred_at'=>now()]);} }
